import 'package:flutter_fractals/core/models/export_options.dart';

void main() {
  group('ExportFormat', () {
    test('extension returns correct file extensions', () {
      expect(ExportFormat.png.extension, 'png');
      expect(ExportFormat.jpg.extension, 'jpg');
      expect(ExportFormat.webp.extension, 'webp');
    });

    test('mimeType returns correct MIME types', () {
      expect(ExportFormat.png.mimeType, 'image/png');
      expect(ExportFormat.jpg.mimeType, 'image/jpeg');
      expect(ExportFormat.webp.mimeType, 'image/webp');
    });
  });

  group('ExportResolution', () {
    test('dimensions returns correct values for preset resolutions', () {
      expect(ExportResolution.hd.dimensions, (1280, 720));
      expect(ExportResolution.fullHd.dimensions, (1920, 1080));
      expect(ExportResolution.quadHd.dimensions, (2560, 1440));
      expect(ExportResolution.uhd4k.dimensions, (3840, 2160));
      expect(ExportResolution.instagram.dimensions, (1080, 1080));
      expect(ExportResolution.instagramStory.dimensions, (1080, 1920));
      expect(ExportResolution.twitter.dimensions, (1200, 675));
    });

    test('screen and custom resolutions return null dimensions', () {
      expect(ExportResolution.screen.dimensions, isNull);
      expect(ExportResolution.custom.dimensions, isNull);
    });

    test('isSocialPreset identifies social presets correctly', () {
      expect(ExportResolution.instagram.isSocialPreset, isTrue);
      expect(ExportResolution.instagramStory.isSocialPreset, isTrue);
      expect(ExportResolution.twitter.isSocialPreset, isTrue);
      expect(ExportResolution.fullHd.isSocialPreset, isFalse);
      expect(ExportResolution.uhd4k.isSocialPreset, isFalse);
    });
  });

  group('ExportOptions', () {
    test('default options have sensible values', () {
      const options = ExportOptions();
      expect(options.format, ExportFormat.png);
      expect(options.resolution, ExportResolution.fullHd);
      expect(options.quality, 95);
      expect(options.embedMetadata, isTrue);
      expect(options.transparentBackground, isFalse);
    });

    test('calculatePixelRatio returns correct ratio for preset resolutions',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      // Portrait screen 400x800 -> Full HD adapts to 1080x1920.
      // Ratios: 1080/400 = 2.7, 1920/800 = 2.4 -> max = 2.7
      final ratio = options.calculatePixelRatio(400, 800);
      expect(ratio, closeTo(2.7, 0.1));
    });

    test('calculatePixelRatio is clamped to 8.0 max', () {
      const options = ExportOptions(resolution: ExportResolution.uhd4k);
      // Screen 100x100 -> would need 38.4 ratio, but clamped to 8
      final ratio = options.calculatePixelRatio(100, 100);
      expect(ratio, 8.0);
    });

    test('calculatePixelRatio sanitizes invalid screen dimensions for presets',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);

      expect(options.calculatePixelRatio(-400, -800), 8.0);
    });

    test('getTargetDimensions returns correct dimensions', () {
      const options = ExportOptions(resolution: ExportResolution.instagram);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1080));
    });

    test('getTargetDimensions adapts preset orientation to screen orientation',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1920));
    });

    test('social preset dimensions preserve platform crop contracts', () {
      const instagramStory = ExportOptions(
        resolution: ExportResolution.instagramStory,
      );
      const twitter = ExportOptions(resolution: ExportResolution.twitter);

      expect(instagramStory.getTargetDimensions(1200, 800), (1080, 1920));
      expect(twitter.getTargetDimensions(400, 800), (1200, 675));
      expect(
        instagramStory.calculatePixelRatio(1200, 800),
        closeTo(2.4, 0.01),
      );
    });

    test('custom resolution uses customWidth and customHeight', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (2000, 1500));
    });

    test('custom resolution ignores non-positive dimensions', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 0,
        customHeight: -10,
      );

      expect(options.getTargetDimensions(400, 800), (400, 800));
      expect(options.calculatePixelRatio(400, 800), 1.0);
    });

    test('custom resolution can fall back one axis at a time', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 0,
      );

      expect(options.getTargetDimensions(400, 800), (2000, 800));
      expect(options.calculatePixelRatio(400, 800), 5.0);
    });

    test('custom resolution clamps huge dimensions to safe image bounds', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 1 << 40,
        customHeight: 1 << 35,
      );

      expect(options.getTargetDimensions(400, 800), (1 << 30, 1 << 30));
      expect(options.calculatePixelRatio(400, 800), 8.0);
    });

    test('screen dimensions used for fallback are at least one pixel', () {
      const options = ExportOptions(resolution: ExportResolution.custom);

      expect(options.getTargetDimensions(0, -20), (1, 1));
      expect(options.calculatePixelRatio(0, -20), 1.0);
    });

    test('copyWith creates new instance with updated values', () {
      const original = ExportOptions();
      final updated = original.copyWith(
        format: ExportFormat.jpg,
        quality: 80,
      );

      expect(updated.format, ExportFormat.jpg);
      expect(updated.quality, 80);
      expect(updated.resolution, original.resolution); // Unchanged
    });

    test('copyWith clears nullable custom dimensions when null is explicit',
        () {
      const original = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );

      final updated = original.copyWith(
        customWidth: null,
        customHeight: null,
      );

      expect(updated.customWidth, isNull);
      expect(updated.customHeight, isNull);
      expect(updated.getTargetDimensions(400, 800), (400, 800));
    });

    test('copyWith clears nullable provenance fields when null is explicit',
        () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(
        metadata: null,
        watermarkText: null,
      );

      expect(updated.metadata, isNull);
      expect(updated.watermarkText, isNull);
    });

    test('copyWith omits nullable provenance fields without clearing them', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(quality: 80);

      expect(updated.metadata, same(metadata));
      expect(updated.watermarkText, 'Flutter Fractals');
    });
  });

  group('ExportMetadata', () {
    test('toExifMap returns expected keys', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );

      final exif = metadata.toExifMap();
      expect(exif, containsPair('Software', contains('Flutter Fractals')));
      expect(exif, containsPair('Artist', 'Flutter Fractals'));
      expect(exif, containsPair('UserComment', contains('mandelbrot')));
    });
  });

  group('ExportPresets', () {
    test('socialShare preset has correct settings', () {
      expect(ExportPresets.socialShare.format, ExportFormat.jpg);
      expect(ExportPresets.socialShare.resolution, ExportResolution.instagram);
      expect(ExportPresets.socialShare.quality, 90);
    });

    test('highQualityPng preset has correct settings', () {
      expect(ExportPresets.highQualityPng.format, ExportFormat.png);
      expect(ExportPresets.highQualityPng.resolution, ExportResolution.uhd4k);
    });

    test('webOptimized preset has correct settings', () {
      expect(ExportPresets.webOptimized.format, ExportFormat.webp);
      expect(ExportPresets.webOptimized.resolution, ExportResolution.fullHd);
      expect(ExportPresets.webOptimized.quality, 85);
    });

    test('transparentOverlay preset has correct settings', () {
      expect(ExportPresets.transparentOverlay.format, ExportFormat.png);
      expect(ExportPresets.transparentOverlay.transparentBackground, isTrue);
    });
  });
}

import 'package:vector_math/vector_math.dart';

/// Represents the view/camera state for fractal rendering.
///
/// This class captures the user's navigation state within a fractal:
/// - For 2D fractals: pan offset and zoom level
/// - For 3D fractals: rotation angles and zoom level
///
/// [FractalViewState] is designed to be stored in presets and serialized,
/// allowing users to save and restore specific viewpoints.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final view = FractalViewState(
///   pan: Vector2(-0.5, 0.2),  // Offset from center
///   zoom: 3.0,                 // 3x magnification
///   rotation: Vector3.zero(), // No rotation (for 2D)
/// );
/// ```
class FractalViewState {
  /// The 2D pan offset from the fractal center.
  ///
  /// For 2D fractals, this determines which part of the complex plane
  /// is visible. Positive X moves right, positive Y moves down.
  ///
  /// Typical range: -3.0 to 3.0 for each axis.
  final Vector2 _pan;

  /// Returns a defensive copy because [Vector2] is mutable.
  Vector2 get pan => Vector2.copy(_pan);

  /// The current zoom/magnification level.
  ///
  /// - Values > 1.0 zoom in (magnify)
  /// - Values < 1.0 zoom out (shrink)
  /// - Value of 1.0 is the default view
  ///
  /// In controller updates, this is typically clamped to [1e-9, 1e12]
  /// to allow deep-zoom workflows.
  final double zoom;

  /// The 3D rotation angles in radians.
  ///
  /// For 3D fractals like Mandelbulb, this controls the camera orientation:
  /// - x: Rotation around the X axis (pitch)
  /// - y: Rotation around the Y axis (yaw)
  /// - z: Rotation around the Z axis (roll)
  ///
  /// For 2D fractals, this is typically [Vector3.zero()].
  final Vector3 _rotation;

  /// Returns a defensive copy because [Vector3] is mutable.
  Vector3 get rotation => Vector3.copy(_rotation);

  /// Creates a [FractalViewState] with specific view parameters.
  ///
  /// All parameters are required to define a complete view state. The supplied
  /// vector instances are copied because [Vector2] and [Vector3] are mutable.
  FractalViewState({
    required Vector2 pan,
    required this.zoom,
    required Vector3 rotation,
  })  : _pan = Vector2.copy(pan),
        _rotation = Vector3.copy(rotation);

  /// Creates the initial/default view state.
  ///
  /// Centers the view with no pan offset, 1x zoom, and no rotation.
  /// This is the starting point when a fractal is first loaded.
  FractalViewState.initial()
      : _pan = Vector2.zero(),
        zoom = 1.0,
        _rotation = Vector3.zero();

  /// Creates a copy of this view state with the given fields replaced.
  ///
  /// Unspecified fields retain their original values.
  ///
  /// Example:
  /// ```dart
  /// final zoomed = view.copyWith(zoom: view.zoom * 2);
  /// ```
  FractalViewState copyWith({
    Vector2? pan,
    double? zoom,
    Vector3? rotation,
  }) {
    return FractalViewState(
      pan: pan ?? _pan,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? _rotation,
    );
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

void main() {
  group('FractalViewState', () {
    group('initial', () {
      test('creates state with zoom 1.0', () {
        final state = FractalViewState.initial();
        expect(state.zoom, 1.0);
      });

      test('creates state with zero pan', () {
        final state = FractalViewState.initial();
        expect(state.pan.x, 0.0);
        expect(state.pan.y, 0.0);
      });

      test('creates state with zero rotation', () {
        final state = FractalViewState.initial();
        expect(state.rotation.x, 0.0);
        expect(state.rotation.y, 0.0);
        expect(state.rotation.z, 0.0);
      });
    });

    group('copyWith', () {
      test('replaces only zoom when specified', () {
        final original = FractalViewState.initial();
        final copy = original.copyWith(zoom: 3.5);

        expect(copy.zoom, 3.5);
        expect(copy.pan.x, original.pan.x);
        expect(copy.pan.y, original.pan.y);
        expect(copy.rotation.x, original.rotation.x);
        expect(copy.rotation.y, original.rotation.y);
        expect(copy.rotation.z, original.rotation.z);
      });

      test('replaces only pan when specified', () {
        final original = FractalViewState.initial();
        final newPan = Vector2(1.5, -0.5);
        final copy = original.copyWith(pan: newPan);

        expect(copy.pan.x, 1.5);
        expect(copy.pan.y, -0.5);
        expect(copy.zoom, original.zoom);
        expect(copy.rotation.x, original.rotation.x);
      });

      test('replaces only rotation when specified', () {
        final original = FractalViewState.initial();
        final newRotation = Vector3(0.1, 0.2, 0.3);
        final copy = original.copyWith(rotation: newRotation);

        expect(copy.rotation.x, closeTo(0.1, 1e-6));
        expect(copy.rotation.y, closeTo(0.2, 1e-6));
        expect(copy.rotation.z, closeTo(0.3, 1e-6));
        expect(copy.zoom, original.zoom);
        expect(copy.pan.x, original.pan.x);
      });

      test('replaces all fields when all specified', () {
        final original = FractalViewState.initial();
        final newPan = Vector2(2.0, 3.0);
        final newRotation = Vector3(0.5, 1.0, 1.5);
        final copy = original.copyWith(
          pan: newPan,
          zoom: 10.0,
          rotation: newRotation,
        );

        expect(copy.zoom, 10.0);
        expect(copy.pan.x, 2.0);
        expect(copy.pan.y, 3.0);
        expect(copy.rotation.x, closeTo(0.5, 1e-6));
        expect(copy.rotation.y, closeTo(1.0, 1e-6));
        expect(copy.rotation.z, closeTo(1.5, 1e-6));
      });

      test('preserves all fields when no args provided', () {
        final original = FractalViewState(
          pan: Vector2(-0.5, 0.2),
          zoom: 3.0,
          rotation: Vector3(0.1, 0.2, 0.3),
        );
        final copy = original.copyWith();

        expect(copy.zoom, original.zoom);
        expect(copy.pan.x, original.pan.x);
        expect(copy.pan.y, original.pan.y);
        expect(copy.rotation.x, original.rotation.x);
        expect(copy.rotation.y, original.rotation.y);
        expect(copy.rotation.z, original.rotation.z);
      });

      test('returns a new instance, not the same reference', () {
        final original = FractalViewState.initial();
        final copy = original.copyWith(zoom: 2.0);
        expect(identical(original, copy), isFalse);
      });
    });

    group('constructor', () {
      test('stores all provided values', () {
        final pan = Vector2(1.0, 2.0);
        final rotation = Vector3(0.3, 0.6, 0.9);
        final state = FractalViewState(pan: pan, zoom: 5.0, rotation: rotation);

        expect(state.zoom, 5.0);
        expect(state.pan.x, 1.0);
        expect(state.pan.y, 2.0);
        expect(state.rotation.x, closeTo(0.3, 1e-6));
        expect(state.rotation.y, closeTo(0.6, 1e-6));
        expect(state.rotation.z, closeTo(0.9, 1e-6));
      });

      test('snapshots mutable vectors supplied by callers', () {
        final pan = Vector2(1.0, 2.0);
        final rotation = Vector3(0.3, 0.6, 0.9);
        final state = FractalViewState(pan: pan, zoom: 5.0, rotation: rotation);

        pan.setValues(7.0, 8.0);
        rotation.setValues(9.0, 10.0, 11.0);

        expect(state.pan.x, 1.0);
        expect(state.pan.y, 2.0);
        expect(state.rotation.x, closeTo(0.3, 1e-6));
        expect(state.rotation.y, closeTo(0.6, 1e-6));
        expect(state.rotation.z, closeTo(0.9, 1e-6));
      });

      test('exposes vector fields as immutable snapshots', () {
        final state = FractalViewState(
          pan: Vector2(1.0, 2.0),
          zoom: 5.0,
          rotation: Vector3(0.3, 0.6, 0.9),
        );

        final exposedPan = state.pan;
        final exposedRotation = state.rotation;
        exposedPan.setValues(7.0, 8.0);
        exposedRotation.setValues(9.0, 10.0, 11.0);

        expect(state.pan, Vector2(1.0, 2.0));
        expect(state.rotation, Vector3(0.3, 0.6, 0.9));
      });
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

FractalViewState _snapshotPresetView(FractalViewState view) {
  return FractalViewState(
    pan: view.pan,
    zoom: view.zoom,
    rotation: view.rotation,
  );
}

Map<String, Object> _snapshotPresetParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: _snapshotPresetParamValue(entry.value),
  });
}

Map<String, Object> _decodePresetParams(Map params) {
  final decoded = <String, Object>{};
  for (final entry in params.entries) {
    final key = entry.key;
    final value = entry.value;
    if (key == null || value == null) continue;
    decoded[key.toString()] = _snapshotPresetParamValue(value as Object);
  }
  return Map<String, Object>.unmodifiable(decoded);
}

Object _snapshotPresetParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? _snapshotPresetParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? _snapshotPresetParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  ///
  /// The supplied view vectors and parameter collections are snapshotted so a
  /// preset remains replayable even when callers mutate their originals.
  FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required Map<String, Object> params,
    required FractalViewState view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  })  : params = _snapshotPresetParams(params),
        view = _snapshotPresetView(view);

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets. Because `null` means
  /// "keep the existing value" for optional fields, set [clearThumbnailPath]
  /// when a copy must remove an existing thumbnail.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
    bool clearThumbnailPath = false,
  }) {
    assert(
      !clearThumbnailPath || thumbnailPath == null,
      'thumbnailPath cannot be provided when clearThumbnailPath is true',
    );
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath:
          clearThumbnailPath ? null : thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: _decodePresetParams(json['params'] as Map),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ??
          DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset =
              FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('FractalPreset JSON', () {
    test('toJson/fromJson round-trips core fields', () {
      final preset = FractalPreset(
        id: 'p1',
        moduleId: 'mandelbrot',
        name: 'Test',
        params: const {
          'iterations': 123,
          'bailout': 4.5,
          'colorScheme': 2,
        },
        view: FractalViewState(
          pan: Vector2(1.25, -3.5),
          zoom: 2.0,
          rotation: Vector3(0.1, 0.2, 0.3),
        ),
        createdAt: DateTime(2026, 1, 2, 3, 4, 5),
        isBuiltIn: true,
        thumbnailPath: 'thumb.png',
      );

      final decoded = FractalPreset.fromJson(preset.toJson());

      expect(decoded.id, preset.id);
      expect(decoded.moduleId, preset.moduleId);
      expect(decoded.name, preset.name);
      expect(decoded.params, preset.params);
      expect(decoded.isBuiltIn, isTrue);
      expect(decoded.thumbnailPath, 'thumb.png');
      // JSON decoding can round-trip through 32-bit floats on some platforms/engines.
      // Keep tolerance slightly loose to avoid flaky CI failures.
      const eps = 1e-6;
      expect(decoded.view.pan.x, closeTo(1.25, eps));
      expect(decoded.view.pan.y, closeTo(-3.5, eps));
      expect(decoded.view.zoom, closeTo(2.0, eps));
      expect(decoded.view.rotation.x, closeTo(0.1, eps));
      expect(decoded.view.rotation.y, closeTo(0.2, eps));
      expect(decoded.view.rotation.z, closeTo(0.3, eps));
      expect(decoded.createdAt.toIso8601String(),
          preset.createdAt.toIso8601String());
    });

    test('fromJson tolerates missing view fields and invalid createdAt', () {
      final decoded = FractalPreset.fromJson({
        'id': 'p2',
        'moduleId': 'mandelbrot',
        'name': 'Broken',
        'params': <String, Object>{'iterations': 1},
        // view intentionally omitted
        'createdAt': 'not-a-date',
      });

      expect(decoded.view.zoom, 1.0);
      expect(decoded.view.pan, equals(Vector2.zero()));
      expect(decoded.view.rotation, equals(Vector3.zero()));
      // Should fall back to "now" and not throw.
      expect(decoded.createdAt, isA<DateTime>());
    });

    test('keeps preset when persisted params contain stale nulls', () {
      final decoded = FractalPreset.fromJson({
        'id': 'stale-null-param',
        'moduleId': 'mandelbrot',
        'name': 'Stale Null Param',
        'params': <String, Object?>{
          'iterations': 120,
          'staleNull': null,
          'colorStops': <Object?>[
            0.0,
            null,
            <String, Object?>{'position': null},
          ],
        },
        'view': <String, Object?>{
          'panX': 0,
          'panY': 0,
          'zoom': 1,
          'rotX': 0,
          'rotY': 0,
          'rotZ': 0,
        },
        'createdAt': '2026-01-01T00:00:00.000Z',
      });

      expect(decoded.id, 'stale-null-param');
      expect(decoded.params, {
        'iterations': 120,
        'colorStops': [
          0.0,
          null,
          {'position': null},
        ],
      });
    });

    test('copyWith can explicitly clear an optional thumbnail path', () {
      final preset = FractalPreset(
        id: 'p1',
        moduleId: 'mandelbrot',
        name: 'With thumbnail',
        params: const {},
        view: FractalViewState.initial(),
        createdAt: DateTime(2026, 1, 1),
        thumbnailPath: 'thumb.png',
      );

      final copied = preset.copyWith(clearThumbnailPath: true);

      expect(copied.thumbnailPath, isNull);
      expect(copied.id, preset.id);
      expect(copied.moduleId, preset.moduleId);
    });

    test('snapshots mutable view vectors and nested params', () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final colorStops = <Object?>[
        0.0,
        <Object, Object?>{
          1: 'one',
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final params = <String, Object>{'colorStops': colorStops};

      final preset = FractalPreset(
        id: 'p1',
        moduleId: 'mandelbrot',
        name: 'Snapshot',
        params: params,
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        createdAt: DateTime(2026, 1, 1),
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      ((colorStops[1] as Map<Object, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      (colorStops[1] as Map<Object, Object?>)[2] = 'two';
      colorStops.add(1.0);

      expect(preset.view.pan.x, 1);
      expect(preset.view.pan.y, 2);
      expect(preset.view.rotation.x, 3);
      expect(preset.view.rotation.y, 4);
      expect(preset.view.rotation.z, 5);
      expect(preset.params, {
        'colorStops': [
          0.0,
          {
            '1': 'one',
            'rgb': [32, 64, 128],
          },
        ],
      });
      expect(
        () => (preset.params['colorStops'] as List<Object?>).add(1.0),
        throwsUnsupportedError,
      );
      expect(
        () => ((preset.params['colorStops'] as List<Object?>)[1]
            as Map<String, Object?>)['rgb'] = <Object?>[],
        throwsUnsupportedError,
      );
    });

    test('listToPrefs/listFromPrefs round-trip and handle empty payload', () {
      expect(FractalPreset.listFromPrefs(null), isEmpty);
      expect(FractalPreset.listFromPrefs(''), isEmpty);

      final presets = [
        FractalPreset(
          id: 'a',
          moduleId: 'mandelbrot',
          name: 'A',
          params: const {'iterations': 120},
          view: FractalViewState.initial(),
          createdAt: DateTime(2026, 1, 1),
        ),
        FractalPreset(
          id: 'b',
          moduleId: 'mandelbrot',
          name: 'B',
          params: const {'iterations': 200},
          view: FractalViewState.initial(),
          createdAt: DateTime(2026, 1, 2),
        ),
      ];

      final payload = FractalPreset.listToPrefs(presets);
      final decoded = FractalPreset.listFromPrefs(payload);

      expect(decoded.map((p) => p.id).toList(), ['a', 'b']);
      expect(decoded[1].params['iterations'], 200);
    });
  });
}

import 'package:equatable/equatable.dart';
import 'package:vector_math/vector_math.dart';

/// Represents the complete rendering parameters for a fractal.
///
/// This class encapsulates all configurable options that affect how a fractal
/// is rendered, including mathematical parameters (power, iterations, bailout),
/// visual settings (color scheme, zoom), and spatial transformations (rotation).
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final params = FractalParams(
///   power: 8.0,
///   iterations: 100,
///   zoom: 2.0,
///   rotation: Vector3(0.5, 0.3, 0.0),
///   mousePos: Vector2.zero(),
/// );
/// ```
class FractalParams extends Equatable {
  /// The mathematical power used in fractal calculations.
  ///
  /// Higher values create more intricate patterns. For Mandelbulb fractals,
  /// values of 8 produce the classic shape, while lower or higher values
  /// create interesting variations.
  ///
  /// Typical range: 2.0 to 12.0
  final double power;

  /// The maximum number of iterations for escape-time calculations.
  ///
  /// Higher iteration counts reveal more detail but require more computation.
  /// Values between 50-200 are typical for interactive rendering.
  final int iterations;

  /// The escape radius threshold for fractal calculations.
  ///
  /// Points that exceed this distance from the origin are considered to have
  /// escaped. Lower values create sharper boundaries.
  ///
  /// Typical range: 1.0 to 4.0
  final double bailout;

  /// The current zoom/magnification level.
  ///
  /// Values greater than 1.0 zoom in, values less than 1.0 zoom out.
  /// Range is typically clamped to 0.1x - 10x.
  final double zoom;

  /// The 3D rotation angles for the fractal view.
  ///
  /// Used for 3D fractals (like Mandelbulb) to control camera orientation.
  /// Each component represents rotation around the X, Y, and Z axes respectively.
  final Vector3 _rotation;

  /// Returns a defensive copy because [Vector3] is mutable.
  Vector3 get rotation => Vector3.copy(_rotation);

  /// The active color scheme index.
  ///
  /// Maps to [AppColorScheme] enum values:
  /// - 0: Fire
  /// - 1: Ocean
  /// - 2: Psychedelic
  /// - 3: Grayscale
  final int colorScheme;

  /// The current mouse/touch position in normalized coordinates.
  ///
  /// Used for interactive effects where the fractal responds to pointer position.
  final Vector2 _mousePos;

  /// Returns a defensive copy because [Vector2] is mutable.
  Vector2 get mousePos => Vector2.copy(_mousePos);

  /// The type of fractal being rendered.
  ///
  /// Determines which algorithm is used for fractal generation.
  final FractalType fractalType;

  /// Creates a new [FractalParams] instance with the specified values.
  ///
  /// The [rotation] and [mousePos] vectors are required as they have no
  /// sensible universal default.
  FractalParams({
    this.power = 8.0,
    this.iterations = 50,
    this.bailout = 2.0,
    this.zoom = 1.0,
    required Vector3 rotation,
    this.colorScheme = 0,
    required Vector2 mousePos,
    this.fractalType = FractalType.mandelbulb,
  })  : _rotation = Vector3.copy(rotation),
        _mousePos = Vector2.copy(mousePos);

  /// Creates a [FractalParams] with sensible default values.
  ///
  /// Useful for initialization when no specific parameters are needed.
  FractalParams.withDefaults()
      : power = 8.0,
        iterations = 50,
        bailout = 2.0,
        zoom = 1.0,
        _rotation = Vector3(0.0, 0.0, 0.0),
        colorScheme = 0,
        _mousePos = Vector2(0.0, 0.0),
        fractalType = FractalType.mandelbulb;

  /// Creates a copy of this [FractalParams] with the given fields replaced.
  ///
  /// All parameters are optional; unspecified parameters retain their
  /// original values.
  FractalParams copyWith({
    double? power,
    int? iterations,
    double? bailout,
    double? zoom,
    Vector3? rotation,
    int? colorScheme,
    Vector2? mousePos,
    FractalType? fractalType,
  }) {
    return FractalParams(
      power: power ?? this.power,
      iterations: iterations ?? this.iterations,
      bailout: bailout ?? this.bailout,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? _rotation,
      colorScheme: colorScheme ?? this.colorScheme,
      mousePos: mousePos ?? _mousePos,
      fractalType: fractalType ?? this.fractalType,
    );
  }

  @override
  List<Object?> get props => [
        power,
        iterations,
        bailout,
        zoom,
        _rotation,
        colorScheme,
        _mousePos,
        fractalType,
      ];
}

/// Available color schemes for fractal rendering.
///
/// Each scheme provides a distinct visual aesthetic for the fractal output.
enum AppColorScheme {
  /// Warm orange-red-yellow gradient, reminiscent of flames.
  fire,

  /// Cool blue-teal gradient, evoking underwater themes.
  ocean,

  /// Vibrant multi-color gradient with high saturation.
  psychedelic,

  /// Black-to-white gradient for a classic mathematical look.
  grayscale;
}

/// Types of fractals available for rendering.
///
/// Each type uses a different mathematical algorithm to generate
/// its characteristic patterns.
enum FractalType {
  /// 3D extension of the Mandelbrot set.
  ///
  /// Creates a bulbous, organic-looking 3D shape through
  /// spherical coordinate mapping.
  mandelbulb,

  /// Box-folding fractal with recursive transformations.
  ///
  /// Creates geometric, box-like structures with infinite detail.
  mandelbox,

  /// Complex-number iteration fractal.
  ///
  /// Uses a constant complex parameter to create varied 2D patterns.
  julia,

  /// Recursive tetrahedron subdivision.
  ///
  /// A 3D fractal created by iteratively removing tetrahedra
  /// from a larger tetrahedron.
  sierpinski;
}

import 'package:flutter_fractals/core/models/fractal_params.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('FractalParams', () {
    test('equality includes fractalType', () {
      final a = FractalParams(
        rotation: Vector3.zero(),
        mousePos: Vector2.zero(),
        fractalType: FractalType.mandelbulb,
      );
      final b = a.copyWith(fractalType: FractalType.julia);

      expect(a, isNot(equals(b)));
    });

    test('snapshots mutable vectors supplied by callers', () {
      final rotation = Vector3(0.1, 0.2, 0.3);
      final mousePos = Vector2(0.4, 0.5);
      final params = FractalParams(rotation: rotation, mousePos: mousePos);

      rotation.setValues(1.0, 2.0, 3.0);
      mousePos.setValues(4.0, 5.0);

      expect(params.rotation, Vector3(0.1, 0.2, 0.3));
      expect(params.mousePos, Vector2(0.4, 0.5));
    });

    test('exposes vector fields as immutable snapshots', () {
      final params = FractalParams(
        rotation: Vector3(0.1, 0.2, 0.3),
        mousePos: Vector2(0.4, 0.5),
      );

      final exposedRotation = params.rotation;
      final exposedMousePos = params.mousePos;
      exposedRotation.setValues(1.0, 2.0, 3.0);
      exposedMousePos.setValues(4.0, 5.0);

      expect(params.rotation, Vector3(0.1, 0.2, 0.3));
      expect(params.mousePos, Vector2(0.4, 0.5));
    });

    test('copyWith snapshots replacement vectors', () {
      final original = FractalParams(
        rotation: Vector3.zero(),
        mousePos: Vector2.zero(),
      );
      final replacementRotation = Vector3(0.1, 0.2, 0.3);
      final replacementMousePos = Vector2(0.4, 0.5);

      final copy = original.copyWith(
        rotation: replacementRotation,
        mousePos: replacementMousePos,
      );

      replacementRotation.setValues(1.0, 2.0, 3.0);
      replacementMousePos.setValues(4.0, 5.0);

      expect(copy.rotation, Vector3(0.1, 0.2, 0.3));
      expect(copy.mousePos, Vector2(0.4, 0.5));
      expect(original.rotation, Vector3.zero());
      expect(original.mousePos, Vector2.zero());
    });
  });
}

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';

/// User-facing renderer backend preference.
///
/// This setting lets users prefer CPU (stable) or GPU (fast) rendering.
///
/// - [RendererBackendMode.auto]: Use policy + health checks (recommended).
/// - [RendererBackendMode.cpuOnly]: Always use CPU renderer.
/// - [RendererBackendMode.gpuOnly]: Always try GPU renderer (debug).
///
/// Stored in SharedPreferences.
enum RendererBackendMode { auto, cpuOnly, gpuOnly }

class RendererSettingsService extends ChangeNotifier {
  static const String _keyBackendMode = 'renderer_backend_mode';

  final SharedPreferences _prefs;

  RendererBackendMode _backendMode;

  RendererSettingsService(this._prefs)
      : _backendMode = _decode(_prefs.getString(_keyBackendMode));

  static Future<RendererSettingsService> create() async {
    final prefs = await SharedPreferences.getInstance();
    return RendererSettingsService(prefs);
  }

  RendererBackendMode get backendMode => _backendMode;

  Future<void> setBackendMode(RendererBackendMode mode) async {
    if (_backendMode == mode) return;
    _backendMode = mode;
    await _prefs.setString(_keyBackendMode, mode.name);
    notifyListeners();
  }

  static RendererBackendMode _decode(String? raw) {
    switch (raw) {
      case 'cpuOnly':
        return RendererBackendMode.cpuOnly;
      case 'gpuOnly':
        return RendererBackendMode.gpuOnly;
      case 'auto':
      default:
        return RendererBackendMode.auto;
    }
  }
}

