/// Replayable kaleidoscope effect state owned by [FractalController].
///
/// Some catalog modules are kaleidoscope-specific and temporarily force the
/// global kaleidoscope canvas effect on with module defaults. Keeping the
/// previous user-controlled effect state separate from the forced module state
/// prevents module switches from leaking kaleidoscope settings into unrelated
/// fractals.
final class FractalKaleidoscopeState {
  static const int defaultSectors = 8;
  static const int forcedModuleSectors = 16;
  static const int defaultMirrorMode = 0;
  static const int forcedModuleMirrorMode = 3;

  final bool enabled;
  final int sectors;
  final bool mirror;
  final double rotation;
  final int mirrorMode;

  const FractalKaleidoscopeState({
    required this.enabled,
    required this.sectors,
    required this.mirror,
    required this.rotation,
    required this.mirrorMode,
  });

  const FractalKaleidoscopeState.defaults()
      : enabled = false,
        sectors = defaultSectors,
        mirror = true,
        rotation = 0.0,
        mirrorMode = defaultMirrorMode;

  FractalKaleidoscopeState copyWith({
    bool? enabled,
    int? sectors,
    bool? mirror,
    double? rotation,
    int? mirrorMode,
  }) {
    return FractalKaleidoscopeState(
      enabled: enabled ?? this.enabled,
      sectors: sectors ?? this.sectors,
      mirror: mirror ?? this.mirror,
      rotation: rotation ?? this.rotation,
      mirrorMode: mirrorMode ?? this.mirrorMode,
    );
  }
}

/// Result of applying module-specific kaleidoscope defaults.
final class FractalKaleidoscopeModuleTransition {
  final FractalKaleidoscopeState effective;
  final FractalKaleidoscopeState? restoreAfterForcedModule;

  const FractalKaleidoscopeModuleTransition({
    required this.effective,
    required this.restoreAfterForcedModule,
  });
}

/// Pure module-switch policy for dedicated kaleidoscope catalog modules.
///
/// Only modules whose IDs use the catalog kaleidoscope prefix force the global
/// kaleidoscope canvas effect. Other fractals may include "kaleidoscope" in
/// their own shader/name without needing the global post-effect defaults.
final class FractalKaleidoscopeModulePolicy {
  static const String forcedModuleIdPrefix = 'kaleidoscope_';

  const FractalKaleidoscopeModulePolicy._();

  static bool isForcedModuleId(String moduleId) =>
      moduleId.startsWith(forcedModuleIdPrefix);

  static FractalKaleidoscopeModuleTransition transitionForModule({
    required String moduleId,
    required FractalKaleidoscopeState current,
    required FractalKaleidoscopeState? restoreAfterForcedModule,
  }) {
    if (isForcedModuleId(moduleId)) {
      return FractalKaleidoscopeModuleTransition(
        effective: current.copyWith(
          enabled: true,
          sectors: FractalKaleidoscopeState.forcedModuleSectors,
          mirrorMode: FractalKaleidoscopeState.forcedModuleMirrorMode,
        ),
        restoreAfterForcedModule: restoreAfterForcedModule ?? current,
      );
    }

    if (restoreAfterForcedModule != null) {
      return FractalKaleidoscopeModuleTransition(
        effective: restoreAfterForcedModule,
        restoreAfterForcedModule: null,
      );
    }

    return FractalKaleidoscopeModuleTransition(
      effective: current,
      restoreAfterForcedModule: null,
    );
  }
}

import 'package:flutter_fractals/features/renderer/providers/fractal_kaleidoscope_state.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FractalKaleidoscopeModulePolicy', () {
    test('forces only dedicated kaleidoscope catalog modules', () {
      expect(
        FractalKaleidoscopeModulePolicy.isForcedModuleId('kaleidoscope_basic'),
        isTrue,
      );
      expect(
        FractalKaleidoscopeModulePolicy.isForcedModuleId(
          'kaleidoscope_fractal',
        ),
        isTrue,
      );

      expect(
        FractalKaleidoscopeModulePolicy.isForcedModuleId(
          'flame-horseshoe-kaleidoscope',
        ),
        isFalse,
      );
      expect(
        FractalKaleidoscopeModulePolicy.isForcedModuleId(
          'f0148_kaleidoscope_julia',
        ),
        isFalse,
      );
    });

    test('leaves embedded-kaleidoscope fractal modules untouched', () {
      const current = FractalKaleidoscopeState(
        enabled: false,
        sectors: 6,
        mirror: true,
        rotation: 0.25,
        mirrorMode: 1,
      );

      final transition = FractalKaleidoscopeModulePolicy.transitionForModule(
        moduleId: 'flame-horseshoe-kaleidoscope',
        current: current,
        restoreAfterForcedModule: null,
      );

      expect(transition.effective.enabled, isFalse);
      expect(transition.effective.sectors, 6);
      expect(transition.effective.rotation, 0.25);
      expect(transition.effective.mirrorMode, 1);
      expect(transition.restoreAfterForcedModule, isNull);
    });
  });
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';

/// Generates one randomized value for a fractal parameter schema.
///
/// This pure helper keeps the controller's randomization data flow visible and
/// replayable in tests without depending on FractalController state. Returned
/// values are normalized through the same schema contract used for presets,
/// replayed state, and direct UI updates.
Object randomFractalParamValue(FractalParameter param, Random random) {
  switch (param.type) {
    case FractalParamType.float:
      final raw = param.min + random.nextDouble() * (param.max - param.min);
      return normalizeFractalParamValue(
        param,
        roundFractalParamValueToStep(raw, param.step),
      );
    case FractalParamType.integer:
      final bounds = FractalNumericParamBounds.fromSchema(param);
      assert(
        bounds.containsInteger,
        'integer parameter bounds must include at least one integer value',
      );
      if (!bounds.containsInteger) {
        return normalizeFractalParamValue(param, param.defaultValue);
      }
      final min = bounds.min.ceil();
      final max = bounds.max.floor();
      return normalizeFractalParamValue(
        param,
        min + random.nextInt(max - min + 1),
      );
    case FractalParamType.enumeration:
      if (param.options.isNotEmpty) {
        final choice = param.options[random.nextInt(param.options.length)];
        return choice.value;
      }
      return param.defaultValue;
    case FractalParamType.boolean:
      return random.nextBool();
  }
}

/// Replayable decision for snapping a randomized float to slider precision.
///
/// Parameter schemas are hand-authored across a large catalog. A malformed
/// non-finite step or raw value must not crash randomization before the shared
/// schema normalizer gets a chance to clamp/fallback the value.
final class FractalParamStepSnapPlan {
  final double inputValue;
  final double step;
  final double value;
  final bool appliedStep;

  const FractalParamStepSnapPlan._({
    required this.inputValue,
    required this.step,
    required this.value,
    required this.appliedStep,
  });

  factory FractalParamStepSnapPlan.fromValue({
    required double value,
    required double step,
  }) {
    if (!value.isFinite || !step.isFinite || step <= 0.0) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    final snapped = (value / step).round() * step;
    if (!snapped.isFinite) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    return FractalParamStepSnapPlan._(
      inputValue: value,
      step: step,
      value: double.parse(snapped.toStringAsFixed(6)),
      appliedStep: true,
    );
  }
}

/// Snaps float randomization to slider step precision while avoiding typical
/// binary floating-point display noise.
double roundFractalParamValueToStep(double value, double step) {
  return FractalParamStepSnapPlan.fromValue(value: value, step: step).value;
}

